   148→        let mut capital_f = [0i32; N];
   149→        let mut capital_g = [0i32; N];
   150→        for i in 0..N {
   151→            f[i] = if f_raw[i] > half_q {
   152→                f_raw[i] - Q
   153→            } else {
   154→                f_raw[i]
   155→            };
   156→            g[i] = if g_raw[i] > half_q {
   157→                g_raw[i] - Q
   158→            } else {
   159→                g_raw[i]
   160→            };
   161→            capital_f[i] = if capital_f_raw[i] > half_q {
   162→                capital_f_raw[i] - Q
   163→            } else {
   164→                capital_f_raw[i]
   165→            };
   166→            capital_g[i] = if capital_g_raw[i] > half_q {
   167→                capital_g_raw[i] - Q
   168→            } else {
   169→                capital_g_raw[i]
   170→            };
   171→        }
   172→
   173→        let f_vec: Vec<i32> = f.iter().copied().collect();
   174→        let g_vec: Vec<i32> = g.iter().copied().collect();
   175→        let capital_f_vec: Vec<i32> = capital_f.iter().copied().collect();
   176→        let capital_g_vec: Vec<i32> = capital_g.iter().copied().collect();
   177→
   178→        // Keep the exact same reconstruction pipeline used during key generation.
   179→        let neg_f: Vec<f64> = f_vec.iter().map(|&x| -(x as f64)).collect();
   180→        let neg_f_cap: Vec<f64> = capital_f_vec.iter().map(|&x| -(x as f64)).collect();
   181→
   182→        let b0: [[Vec<f64>; 2]; 2] = [
   183→            [g_vec.iter().map(|&x| x as f64).collect(), neg_f],
   184→            [capital_g_vec.iter().map(|&x| x as f64).collect(), neg_f_cap],
   185→        ];
   186→
   187→        let b0_fft = [
   188→            [fft(&b0[0][0]), fft(&b0[0][1])],
   189→            [fft(&b0[1][0]), fft(&b0[1][1])],
   190→        ];
   191→
   192→        let g0 = gram(&b0);
   193→        let g0_fft = [
   194→            [fft(&g0[0][0]), fft(&g0[0][1])],
   195→            [fft(&g0[1][0]), fft(&g0[1][1])],
   196→        ];
   197→
   198→        let mut tree = ffldl_fft(&g0_fft);
   199→        normalize_tree(&mut tree, SIGMA);
   200→
   201→        Ok(SecretKey {
   202→            f,
   203→            g,
   204→            capital_f,
   205→            capital_g,
   206→            b0_fft,
   207→            tree,
   208→        })
   209→    }
   210→}
   211→
   212→impl VerifyingKey {
   213→    /// Create a verifying key from raw h polynomial.
   214→    pub fn from_h(h: [i32; N]) -> Self {
   215→        VerifyingKey { h }
   216→    }
   217→
   218→    /// Get a reference to the raw public key polynomial h.
   219→    pub fn h(&self) -> &[i32; N] {
   220→        &self.h
   221→    }
   222→
   223→    /// Serialize the verifying key to bytes.
   224→    pub fn to_bytes(&self) -> [u8; PUBLIC_KEY_LEN] {
   225→        let vec = serialize_public_key(&self.h);
   226→        let mut arr = [0u8; PUBLIC_KEY_LEN];
   227→        arr.copy_from_slice(&vec);
   228→        arr
   229→    }
   230→
   231→    /// Deserialize a verifying key from bytes.
   232→    pub fn from_bytes(bytes: &[u8; PUBLIC_KEY_LEN]) -> Result<Self, FalconError> {
   233→        let h = deserialize_public_key(bytes).ok_or(FalconError::InvalidPublicKey)?;
   234→        Ok(VerifyingKey { h })
   235→    }
   236→}
