   238→impl Signature {
   239→    /// Create a signature from raw components.
   240→    pub fn from_components(header: u8, salt: [u8; SALT_LEN], s1_enc: Vec<u8>) -> Self {
   241→        Signature {
   242→            header,
   243→            salt,
   244→            s1_enc,
   245→        }
   246→    }
   247→
   248→    /// Serialize the signature to bytes.
   249→    pub fn to_bytes(&self) -> Vec<u8> {
   250→        let mut bytes = Vec::with_capacity(HEAD_LEN + SALT_LEN + self.s1_enc.len());
   251→        bytes.push(self.header);
   252→        bytes.extend_from_slice(&self.salt);
   253→        bytes.extend_from_slice(&self.s1_enc);
   254→        bytes
   255→    }
   256→
   257→    /// Return a reference to the random salt embedded in the signature.
   258→    ///
   259→    /// The salt is the 40-byte random value that was generated (or provided)
   260→    /// at signing time. It is also embedded in the serialized signature bytes.
   261→    pub fn salt(&self) -> &[u8; SALT_LEN] {
   262→        &self.salt
   263→    }
   264→
   265→    /// Deserialize a signature from bytes.
   266→    pub fn from_bytes(bytes: &[u8]) -> Result<Self, FalconError> {
   267→        if bytes.len() < HEAD_LEN + SALT_LEN {
   268→            return Err(FalconError::InvalidSignature);
   269→        }
   270→
   271→        let header = bytes[0];
   272→        if header != 0x30 + LOGN {
   273→            return Err(FalconError::InvalidSignature);
   274→        }
   275→
   276→        let mut salt = [0u8; SALT_LEN];
   277→        salt.copy_from_slice(&bytes[HEAD_LEN..HEAD_LEN + SALT_LEN]);
   278→
   279→        let s1_enc = bytes[HEAD_LEN + SALT_LEN..].to_vec();
   280→
   281→        Ok(Signature {
   282→            header,
   283→            salt,
   284→            s1_enc,
   285→        })
   286→    }
   287→}
   288→
   289→/// Falcon-512 signature scheme parameterized by hash function.
   290→///
   291→/// The `Falcon` struct provides the core cryptographic operations:
   292→/// key generation, signing, and verification.
   293→///
   294→/// # Type Parameter
   295→///
   296→/// - `H`: The hash function used to map messages to polynomials.
   297→///   Use [`Shake256Hash`](crate::hash_to_point::Shake256Hash) for standard
   298→///   Falcon or [`PoseidonHashToPoint`](crate::poseidon_hash::PoseidonHashToPoint) for
   299→///   Starknet compatibility.
   300→///
   301→/// # Example
   302→///
   303→/// ```rust,ignore
   304→/// use falcon_rs::falcon::Falcon;
   305→/// use falcon_rs::hash_to_point::Shake256Hash;
   306→///
   307→/// let (sk, vk) = Falcon::<Shake256Hash>::keygen();
   308→/// let sig = Falcon::<Shake256Hash>::sign(&sk, b"message");
   309→/// assert!(Falcon::<Shake256Hash>::verify(&vk, b"message", &sig).unwrap());
   310→/// ```
   311→pub struct Falcon<H: HashToPoint> {
   312→    _marker: PhantomData<H>,
   313→}
   314→
   315→impl<H: HashToPoint> Falcon<H> {
   316→    /// Generate a new keypair using system randomness.
   317→    ///
   318→    /// Creates a fresh Falcon-512 keypair using the system's cryptographically
   319→    /// secure random number generator.
   320→    ///
   321→    /// # Returns
   322→    ///
   323→    /// A tuple of (secret key, verifying key).
   324→    ///
   325→    /// # Panics
   326→    ///
   327→    /// Panics if the system RNG fails to provide random bytes.
   328→    #[cfg(feature = "shake")]
   329→    pub fn keygen() -> (SecretKey, VerifyingKey) {
   330→        use getrandom::getrandom;
   331→        let mut seed = [0u8; 32];
   332→        getrandom(&mut seed).expect("Failed to get random bytes");
   333→        Self::keygen_with_seed(&seed)
   334→    }
   335→
   336→    /// Generate a new keypair with a provided seed.
   337→    ///
   338→    /// Creates a deterministic Falcon-512 keypair from the given seed.
   339→    /// The same seed will always produce the same keypair, which is
   340→    /// useful for testing and key recovery.
   341→    ///
   342→    /// # Arguments
   343→    ///
   344→    /// * `seed` - A seed slice (up to 56 bytes used; shorter seeds are zero-padded)
   345→    ///
   346→    /// # Returns
   347→    ///
   348→    /// A tuple of (secret key, verifying key).
   349→    pub fn keygen_with_seed(seed: &[u8]) -> (SecretKey, VerifyingKey) {
   350→        // Create a deterministic RNG from the seed
   351→        let mut full_seed = [0u8; SEED_LEN];
   352→        let copy_len = seed.len().min(SEED_LEN);
   353→        full_seed[..copy_len].copy_from_slice(&seed[..copy_len]);
   354→        let mut rng = ChaCha20::new(&full_seed);
   355→        let mut random_bytes = |n: usize| rng.random_bytes(n);
   356→
   357→        Self::keygen_with_rng(&mut random_bytes)
   358→    }
   359→
   360→    /// Generate a new keypair with a provided random byte source.
   361→    ///
   362→    /// Creates a Falcon-512 keypair using a custom source of randomness.
   363→    /// This is the most flexible key generation method, useful for
   364→    /// deterministic testing or custom RNG implementations.
   365→    ///
   366→    /// # Arguments
   367→    ///
   368→    /// * `random_bytes` - A closure that returns `n` random bytes when called
   369→    ///
   370→    /// # Returns
   371→    ///
   372→    /// A tuple of (secret key, verifying key).
   373→    pub fn keygen_with_rng<F: FnMut(usize) -> Vec<u8>>(
   374→        random_bytes: &mut F,
   375→    ) -> (SecretKey, VerifyingKey) {
   376→        // Generate NTRU polynomials
   377→        let (f, g, capital_f, capital_g) = ntru_gen(random_bytes);
   378→
   379→        // Compute public key h = g/f mod (x^n + 1, q)
   380→        let f_vec: Vec<i32> = f.iter().copied().collect();
   381→        let g_vec: Vec<i32> = g.iter().copied().collect();
   382→        let h_vec = div_zq(&g_vec, &f_vec).expect("f should be invertible");
   383→        let mut h = [0i32; N];
   384→        h.copy_from_slice(&h_vec);
   385→
   386→        // Compute basis B0 = [[g, -f], [G, -F]] in coefficient representation
   387→        // Note: Use regular negation, NOT modular negation (neg_zq), for the Gram matrix
   388→        let neg_f: Vec<f64> = f_vec.iter().map(|&x| -(x as f64)).collect();
   389→        let neg_f_cap: Vec<f64> = capital_f.iter().map(|&x| -(x as f64)).collect();
   390→
   391→        // B0 in coefficient representation (f64 for Gram computation)
   392→        let b0: [[Vec<f64>; 2]; 2] = [
   393→            [g_vec.iter().map(|&x| x as f64).collect(), neg_f],
   394→            [capital_g.iter().map(|&x| x as f64).collect(), neg_f_cap],
   395→        ];
   396→
   397→        // Convert B0 to FFT representation (for use in signing)
   398→        let b0_fft = [
   399→            [fft(&b0[0][0]), fft(&b0[0][1])],
   400→            [fft(&b0[1][0]), fft(&b0[1][1])],
   401→        ];
   402→
   403→        // Compute Gram matrix G0 = B0 * B0^* in coefficient representation
   404→        // (matching Python's approach: gram() in coef domain, then FFT)
   405→        let g0 = gram(&b0);
   406→        let g0_fft = [
   407→            [fft(&g0[0][0]), fft(&g0[0][1])],
   408→            [fft(&g0[1][0]), fft(&g0[1][1])],
   409→        ];
   410→
   411→        // Build ffLDL tree
   412→        let mut tree = ffldl_fft(&g0_fft);
   413→        normalize_tree(&mut tree, SIGMA);
   414→
   415→        let sk = SecretKey {
   416→            f,
   417→            g,
   418→            capital_f,
   419→            capital_g,
   420→            b0_fft,
   421→            tree,
   422→        };
   423→
   424→        let vk = VerifyingKey { h };
   425→
   426→        (sk, vk)
   427→    }
   428→
   429→    /// Sign a message.
   430→    ///
   431→    /// Creates a Falcon-512 signature over the given message using
   432→    /// the secret key. A fresh random salt is generated for each signature.
   433→    ///
   434→    /// # Arguments
   435→    ///
   436→    /// * `sk` - The secret key to sign with
   437→    /// * `message` - The message bytes to sign
   438→    ///
   439→    /// # Returns
   440→    ///
   441→    /// A signature that can be verified with the corresponding verifying key.
   442→    ///
   443→    /// # Panics
   444→    ///
   445→    /// Panics if the system RNG fails to provide random bytes.
   446→    #[cfg(feature = "shake")]
   447→    pub fn sign(sk: &SecretKey, message: &[u8]) -> Signature
   448→    where
   449→        H: HashToPoint<Input = u8>,
   450→    {
   451→        use getrandom::getrandom;
   452→
   453→        // Generate random salt
   454→        let mut salt = [0u8; SALT_LEN];
   455→        getrandom(&mut salt).expect("Failed to get random bytes");
   456→
   457→        Self::sign_with_salt(sk, message, &salt)
   458→    }
   459→
   460→    /// Sign a message with a provided salt.
   461→    ///
   462→    /// Creates a Falcon-512 signature using a deterministic salt.
   463→    /// This is useful for testing or when reproducible signatures are needed.
   464→    ///
   465→    /// # Arguments
   466→    ///
   467→    /// * `sk` - The secret key to sign with
   468→    /// * `message` - The message bytes to sign
   469→    /// * `salt` - A 40-byte salt value
   470→    ///
   471→    /// # Returns
   472→    ///
   473→    /// A signature that can be verified with the corresponding verifying key.
   474→    ///
   475→    /// # Note
   476→    ///
   477→    /// Using the same salt for different messages may leak information
   478→    /// about the secret key. In production, prefer [`sign`](Self::sign).
   479→    pub fn sign_with_salt(sk: &SecretKey, message: &[u8], salt: &[u8; SALT_LEN]) -> Signature
   480→    where
   481→        H: HashToPoint<Input = u8>,
   482→    {
   483→        let hashed = H::hash_to_point(message, salt);
   484→        let hashed_i32: Vec<i32> = hashed.iter().map(|&x| x as i32).collect();
   485→
   486→        // Initialize seed from salt (seed persists across iterations)
   487→        let mut seed = [0u8; SEED_LEN];
   488→        seed[..SALT_LEN].copy_from_slice(salt);
   489→
   490→        // Signing loop - repeat until we find a short enough signature
   491→        loop {
   492→            let mut rng = ChaCha20::new(&seed);
   493→            let mut random_bytes = |n: usize| rng.random_bytes(n);
   494→
   495→            // Sample preimage
   496→            let (s0, s1) = Self::sample_preimage(sk, &hashed_i32, &mut random_bytes);
   497→
   498→            // Check Euclidean norm
   499→            let s0_slice: &[i32] = &s0;
   500→            let s1_slice: &[i32] = &s1;
   501→            let norm = sqnorm(&[s0_slice, s1_slice]);
   502→
   503→            if norm <= SIG_BOUND {
   504→                // Try to compress s1
   505→                let slen = SIG_BYTELEN - HEAD_LEN - SALT_LEN;
   506→                if let Some(s1_enc) = compress(&s1, slen) {
   507→                    return Signature {
   508→                        header: 0x30 + LOGN,
   509→                        salt: *salt,
   510→                        s1_enc,
   511→                    };
   512→                }
   513→            }
   514→
   515→            // If norm too large or compression failed, try again with different randomness
   516→            // Advance the seed using RNG output
   517→            seed[SALT_LEN..].copy_from_slice(&rng.random_bytes(SEED_LEN - SALT_LEN)[..]);
   518→        }
   519→    }
   520→
   521→    /// Sign a pre-computed hash point, returning raw (s0, s1) polynomials.
   522→    ///
   523→    /// This enables signing with custom hash functions (e.g., Poseidon)
   524→    /// where the hash-to-point is computed externally.
   525→    ///
   526→    /// # Arguments
   527→    ///
   528→    /// * `sk` - The secret key
   529→    /// * `hash_point` - Pre-computed hash point (512 coefficients in [0, Q))
   530→    /// * `seed` - 56-byte seed for the sampling PRNG
   531→    ///
   532→    /// # Returns
   533→    ///
   534→    /// `(s0, s1)` where s0 + s1*h = hash_point (mod q) and ||(s0, s1)|| is small.
   535→    /// Coefficients are signed integers (centered around 0).
   536→    pub fn sign_prehashed(
   537→        sk: &SecretKey,
   538→        hash_point: &[i16; N],
   539→        seed: &[u8; SEED_LEN],
   540→    ) -> (Vec<i32>, Vec<i32>) {
   541→        let hashed_i32: Vec<i32> = hash_point.iter().map(|&x| x as i32).collect();
   542→        let mut current_seed = *seed;
   543→
   544→        loop {
   545→            let mut rng = ChaCha20::new(&current_seed);
   546→            let mut random_bytes = |n: usize| rng.random_bytes(n);
   547→
   548→            let (s0, s1) = Self::sample_preimage(sk, &hashed_i32, &mut random_bytes);
   549→
   550→            let s0_slice: &[i32] = &s0;
   551→            let s1_slice: &[i32] = &s1;
   552→            let norm = sqnorm(&[s0_slice, s1_slice]);
   553→
   554→            if norm <= SIG_BOUND {
   555→                return (s0, s1);
   556→            }
   557→
   558→            // Advance seed
   559→            current_seed[SALT_LEN..]
   560→                .copy_from_slice(&rng.random_bytes(SEED_LEN - SALT_LEN)[..]);
   561→        }
   562→    }
   563→
   564→    /// Sample a short preimage s such that s0 + s1*h = point.
   565→    fn sample_preimage<F: FnMut(usize) -> Vec<u8>>(
   566→        sk: &SecretKey,
   567→        point: &[i32],
   568→        random_bytes: &mut F,
   569→    ) -> (Vec<i32>, Vec<i32>) {
   570→        let [[a, b], [c, d]] = &sk.b0_fft;
   571→
   572→        // Compute t_fft = (point, 0) * B0^(-1)
   573→        // Because the inverse of B0 has a specific form, we can optimize
   574→        let point_fft = fft(&point.iter().map(|&x| x as f64).collect::<Vec<_>>());
   575→        let q_f64 = Q as f64;
   576→
   577→        let t0_fft: Vec<Complex> = point_fft
   578→            .iter()
   579→            .zip(d.iter())
   580→            .map(|(&p, &d_i)| {
   581→                Complex::new(
   582→                    p.re * d_i.re / q_f64 - p.im * d_i.im / q_f64,
   583→                    p.re * d_i.im / q_f64 + p.im * d_i.re / q_f64,
   584→                )
   585→            })
   586→            .collect();
   587→
   588→        let t1_fft: Vec<Complex> = point_fft
   589→            .iter()
   590→            .zip(b.iter())
   591→            .map(|(&p, &b_i)| {
   592→                let neg_p = Complex::new(-p.re, -p.im);
   593→                Complex::new(
   594→                    (neg_p.re * b_i.re - neg_p.im * b_i.im) / q_f64,
   595→                    (neg_p.re * b_i.im + neg_p.im * b_i.re) / q_f64,
   596→                )
   597→            })
   598→            .collect();
   599→
   600→        let t_fft = [t0_fft, t1_fft];
   601→
   602→        // Sample z using ffsampling
   603→        let z_fft = ffsampling_fft(&t_fft, &sk.tree, SIGMIN, random_bytes);
   604→
   605→        // Compute v = z * B0
   606→        let v0_fft = add_fft(&mul_fft(&z_fft[0], a), &mul_fft(&z_fft[1], c));
   607→        let v1_fft = add_fft(&mul_fft(&z_fft[0], b), &mul_fft(&z_fft[1], d));
   608→
   609→        let v0_float = ifft(&v0_fft);
   610→        let v1_float = ifft(&v1_fft);
   611→
   612→        let v0: Vec<i32> = v0_float.iter().map(|&x| x.round() as i32).collect();
   613→        let v1: Vec<i32> = v1_float.iter().map(|&x| x.round() as i32).collect();
   614→
   615→        // s = (point, 0) - v
   616→        // s0 = point - v0, s1 = -v1
   617→        let s0: Vec<i32> = point.iter().zip(v0.iter()).map(|(&p, &v)| p - v).collect();
   618→        let s1: Vec<i32> = v1.iter().map(|&v| -v).collect();
   619→
   620→        (s0, s1)
   621→    }
   622→
   623→    /// Verify a signature.
   624→    ///
   625→    /// Checks that a signature is valid for the given message and verifying key.
   626→    ///
   627→    /// # Arguments
   628→    ///
   629→    /// * `vk` - The verifying key (public key)
   630→    /// * `message` - The message that was supposedly signed
   631→    /// * `sig` - The signature to verify
   632→    ///
   633→    /// # Returns
   634→    ///
   635→    /// - `Ok(true)` if the signature is valid
   636→    /// - `Ok(false)` if the signature is mathematically invalid (wrong key or message)
   637→    /// - `Err(FalconError)` if the signature is malformed
   638→    pub fn verify(vk: &VerifyingKey, message: &[u8], sig: &Signature) -> Result<bool, FalconError>
   639→    where
   640→        H: HashToPoint<Input = u8>,
   641→    {
   642→        // Decompress s1
   643→        let s1 = decompress(&sig.s1_enc, N).ok_or(FalconError::DecompressionFailed)?;
   644→
   645→        // Hash the message
   646→        let hashed = H::hash_to_point(message, &sig.salt);
   647→        let hashed_i32: Vec<i32> = hashed.iter().map(|&x| x as i32).collect();
   648→
   649→        // Compute s0 = hashed - s1 * h
   650→        let h_vec: Vec<i32> = vk.h.iter().copied().collect();
   651→        let s1_h = mul_zq(&s1, &h_vec);
   652→        let s0 = sub_zq(&hashed_i32, &s1_h);
   653→
   654→        // Normalize s0 coefficients to (-q/2, q/2]
   655→        let s0_centered: Vec<i32> = s0
   656→            .iter()
   657→            .map(|&c| {
   658→                let c = c.rem_euclid(Q);
   659→                if c > Q / 2 {
   660→                    c - Q
   661→                } else {
   662→                    c
   663→                }
   664→            })
   665→            .collect();
   666→
   667→        // Check signature norm
   668→        let s0_slice: &[i32] = &s0_centered;
   669→        let s1_slice: &[i32] = &s1;
   670→        let norm = sqnorm(&[s0_slice, s1_slice]);
   671→
   672→        if norm > SIG_BOUND {
   673→            return Ok(false);
   674→        }
   675→
   676→        Ok(true)
   677→    }
   678→}
