   683→    use crate::hash_to_point::Shake256Hash;
   684→
   685→    /// `SecretKey::from_bytes` must reconstruct a functionally equivalent key:
   686→    /// signing with the reconstructed key and verifying with the original vk must succeed.
   687→    #[test]
